import {
  MARKER_HALF_WIDTH,
  SQUARE_HEIGHT,
  TRIANGLE_HEIGHT,
} from '../constants.js';

export const calculateRightMarkerVertexes = (
  x: number,
  y: number,
  width: number,
) => {
  const leftXValues = x - width;
  const rightXValues = x;
  const bottomYValues = y + SQUARE_HEIGHT;

  const bottomRightVertex = {
    x: rightXValues,
    y: bottomYValues + TRIANGLE_HEIGHT,
  };
  const triangleBottomLeftJoint = {
    x: rightXValues - MARKER_HALF_WIDTH,
    y: bottomYValues,
  };
  const bottomLeftVertex = { x: leftXValues, y: bottomYValues };
  const topLeftVertex = { x: leftXValues, y };
  const topRightVertex = { x: rightXValues, y };

  return [
    bottomRightVertex,
    triangleBottomLeftJoint,
    bottomLeftVertex,
    topLeftVertex,
    topRightVertex,
  ];
};
